{
  "version": 1,
  "hooks": {
    "beforeShellExecution": [
      {
        "type": "prompt",
        "matcher": "git commit",
        "prompt": "Pre-Commit Guard: run npm test before committing. If tests fail, fix them and do not commit until the suite is green."
      }
    ]
  }
}

{
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "prompt",
            "prompt": "Pre-Commit Guard: if this is a git commit, run npm test first. Block the commit if tests fail."
          }
        ]
      }
    ]
  }
}
